#include <gauxc/gauxc_config.hpp>
#ifdef GAUXC_HAS_HDF5

#include <gauxc/external/cube.hpp>
#include <gauxc/exceptions.hpp>

#include <highfive/H5File.hpp>

#include <vector>

namespace GauXC {

void write_cube_hdf5(const std::string& path,
                     const Molecule& mol,
                     const CubeGrid& grid,
                     const double* field,
                     const std::string& comment) {
  if (grid.num_points() <= 0) {
    GAUXC_GENERIC_EXCEPTION("write_cube_hdf5: grid has zero points.");
  }
  if (field == nullptr) {
    GAUXC_GENERIC_EXCEPTION("write_cube_hdf5: null field pointer.");
  }

  HighFive::File file(path, HighFive::File::Overwrite);

  // --- Field: 3D dataset (nx, ny, nz) ---
  const auto nx = static_cast<size_t>(grid.nx);
  const auto ny = static_cast<size_t>(grid.ny);
  const auto nz = static_cast<size_t>(grid.nz);

  auto ds_field = file.createDataSet<double>(
      "field", HighFive::DataSpace({nx, ny, nz}));
  ds_field.write_raw(field);

  // Comment attribute on /field.
  const std::string cmt =
      comment.empty() ? "Cube field generated by GauXC" : comment;
  ds_field.createAttribute("comment", cmt);

  // --- Grid metadata ---
  auto grp_grid = file.createGroup("grid");
  grp_grid.createDataSet("origin",
      std::vector<double>(grid.origin.begin(), grid.origin.end()));
  grp_grid.createDataSet("spacing",
      std::vector<double>(grid.spacing.begin(), grid.spacing.end()));
  grp_grid.createDataSet("shape",
      std::vector<int64_t>{grid.nx, grid.ny, grid.nz});

  // --- Atoms ---
  const size_t natom = mol.size();
  auto grp_atoms = file.createGroup("atoms");

  std::vector<int64_t> atomic_numbers(natom);
  std::vector<double> coords(natom * 3);
  for (size_t i = 0; i < natom; ++i) {
    atomic_numbers[i] = static_cast<int64_t>(mol[i].Z.get());
    coords[3 * i + 0] = mol[i].x;
    coords[3 * i + 1] = mol[i].y;
    coords[3 * i + 2] = mol[i].z;
  }

  grp_atoms.createDataSet("Z", atomic_numbers);
  grp_atoms.createDataSet<double>("coords",
      HighFive::DataSpace({natom, 3ul})).write_raw(coords.data());
}

}  // namespace GauXC

#endif  // GAUXC_HAS_HDF5
